// Calculate target bid/ask prices based on midpoint and configurable spread
const priceData = $input.first().json;

// === CONFIGURABLE PARAMETERS ===
const SPREAD_WIDTH = 0.02;    // 2 cents each side of midpoint
const ORDER_SIZE = 50;         // shares per order
const DRIFT_THRESHOLD = 0.01;  // 1 cent drift before replacing orders
// ================================

const midpoint = Number(priceData.midpoint || priceData.price || 0.5);
const currentSpread = priceData.spread || 'N/A';

// Calculate target prices, clamped to valid range [0.01, 0.99]
const targetBid = Math.max(0.01, Math.min(0.99, midpoint - SPREAD_WIDTH));
const targetAsk = Math.max(0.01, Math.min(0.99, midpoint + SPREAD_WIDTH));

return [{
  json: {
    midpoint,
    currentSpread,
    targetBid: Number(targetBid.toFixed(3)),
    targetAsk: Number(targetAsk.toFixed(3)),
    orderSize: ORDER_SIZE,
    driftThreshold: DRIFT_THRESHOLD,
    spreadWidth: SPREAD_WIDTH,
    orderBook: priceData.orderBook || null
  }
}];

// Compare desired bid/ask with existing orders, determine if replacement needed
const orders = $input.all();
const targets = $('Calculate Bid/Ask').first().json;

const DRIFT = targets.driftThreshold;
let needsReplacement = false;
let staleOrderIds = [];
let existingBid = null;
let existingAsk = null;

// Find our existing bid and ask orders
for (const item of orders) {
  const o = item.json;
  if (!o.orderId && !o.id) continue;

  const price = Number(o.price || 0);
  const side = (o.side || '').toUpperCase();

  if (side === 'BUY' || price < targets.midpoint) {
    existingBid = { id: o.orderId || o.id, price, side: 'BUY' };
  } else if (side === 'SELL' || price > targets.midpoint) {
    existingAsk = { id: o.orderId || o.id, price, side: 'SELL' };
  }
}

// Check if bid has drifted
if (existingBid && Math.abs(existingBid.price - targets.targetBid) > DRIFT) {
  staleOrderIds.push(existingBid.id);
  needsReplacement = true;
}
if (!existingBid) needsReplacement = true;

// Check if ask has drifted
if (existingAsk && Math.abs(existingAsk.price - targets.targetAsk) > DRIFT) {
  staleOrderIds.push(existingAsk.id);
  needsReplacement = true;
}
if (!existingAsk) needsReplacement = true;

// Estimate daily reward (rough: spread * size * fills_per_day * 3x multiplier)
const estimatedDailyReward = (targets.spreadWidth * 2 * targets.orderSize * 24 * 0.1 * 3).toFixed(2);

return [{
  json: {
    needsReplacement,
    staleOrderIds,
    staleOrderId: staleOrderIds[0] || '',
    existingBid: existingBid ? existingBid.price : null,
    existingAsk: existingAsk ? existingAsk.price : null,
    targetBid: targets.targetBid,
    targetAsk: targets.targetAsk,
    orderSize: targets.orderSize,
    midpoint: targets.midpoint,
    currentSpread: targets.currentSpread,
    estimatedDailyReward
  }
}];

